module.exports=[50645,a=>{a.n(a.i(27572))},43619,a=>{a.n(a.i(79962))},13718,a=>{a.n(a.i(85523))},18198,a=>{a.n(a.i(45518))},62212,a=>{a.n(a.i(66114))},49409,a=>{"use strict";a.s(["mediaAssets",0,[{id:"portrait-gallery",title:"Bộ chân dung Lê Duẩn theo từng giai đoạn",category:"image",priority:"core",section:"Nhân vật trung tâm",source:"BTLSQG / Báo Nhân Dân / TTXVN",note:"Dùng cho hero banner, gallery chân dung, popup tiểu sử và các khung chuyển cảnh giữa các phòng.",usage:"Chọn 1 ảnh hero ngang, 1 ảnh bán thân trang trọng và 6-8 ảnh tư liệu theo giai đoạn 1930, 1954, 1960, 1968, 1975, 1976-1986.",historicalContext:"Đây là trục thị giác quan trọng nhất của toàn bộ bảo tàng vì giúp người xem nhìn rõ tiến trình từ nhà hoạt động cách mạng đến nhà lãnh đạo cao nhất của Đảng.",thumbnail:"/assets/media/portrait.svg",verified:!0,sourceLinks:[{label:"BTLSQG: Lê Duẩn qua tư liệu, hiện vật",href:"https://baotanglichsu.vn/vi/Articles/3097/20935/tong-bi-thu-le-duan-qua-tu-lieu-hien-vat-bao-quan-tai-bao-tang-lich-su-quoc-gia.html"},{label:"BTLSQG: Triển lãm Lê Duẩn",href:"https://baotanglichsu.vn/vi/Articles/3098/58617/trien-lam-le-duan-nha-lanh-djao-kiet-xuat-nguoi-hoc-tro-loi-lac-cua-chu-tich-ho-chi-minh.html"}]},{id:"quang-tri-memorial",title:"Ảnh quê hương và khu lưu niệm tại Quảng Trị",category:"image",priority:"core",section:"Quê hương & Tuổi trẻ",source:"BTLSQG / Báo Nhân Dân",note:"Phục vụ phòng mở đầu, bản đồ quê hương, panel tiểu sử và phần giới thiệu về môi trường hình thành nhân cách.",usage:"Cần 1 ảnh toàn cảnh khu lưu niệm, 2-3 ảnh nhà lưu niệm hoặc không gian thờ tự, 1 bản đồ Quảng Trị đầu thế kỷ XX.",historicalContext:"Nhóm ảnh này giúp đặt Lê Duẩn vào không gian xã hội - văn hóa cụ thể của Quảng Trị, thay vì chỉ mở đầu bằng chân dung rời rạc.",thumbnail:"/assets/media/quang-tri-home.svg",verified:!0,sourceLinks:[{label:"BTLSQG: 110 năm ngày sinh Tổng Bí thư Lê Duẩn",href:"https://baotanglichsu.vn/vi/Articles/3098/72238/110-nam-ngay-sinh-tong-bi-thu-le-duan-7-4-1907-7-4-2017.html"},{label:"Nhân Dân English: 110th birthday of Le Duan",href:"https://en.nhandan.vn/the-110th-birthday-anniversary-of-party-general-secretary-le-duan-celebrated-post30257.html"}]},{id:"prison-archive",title:"Tư liệu nhà tù Hỏa Lò, Sơn La, Côn Đảo",category:"image",priority:"core",section:"Hoạt động Cách mạng (1930-1945)",source:"BTLSQG / Di tích nhà tù / Báo chính thống",note:"Dùng cho khu “những năm tháng giam cầm”, phù hợp với ảnh hồ sơ, buồng giam, hiện vật tù chính trị và trích dẫn hồi ức.",usage:"Cần 1 ảnh hồ sơ, 2 ảnh di tích, 1 ảnh hiện vật tù chính trị và 1 ảnh đồ họa minh họa tuyến giam giữ.",historicalContext:"Đây là nhóm tư liệu cho thấy sức bền chính trị và tinh thần của thế hệ cách mạng tiền bối, đồng thời tạo chiều sâu cảm xúc trong hành trình bảo tàng.",thumbnail:"/assets/media/prison-years.svg",verified:!0,sourceLinks:[{label:"BTLSQG: Lê Duẩn qua tư liệu, hiện vật",href:"https://baotanglichsu.vn/vi/Articles/3097/20935/tong-bi-thu-le-duan-qua-tu-lieu-hien-vat-bao-quan-tai-bao-tang-lich-su-quoc-gia.html"}]},{id:"south-thesis-facsimile",title:"Facsimile Đề cương Cách mạng miền Nam",category:"image",priority:"core",section:"“Kiến trúc sư” Thống nhất",source:"Báo Nhân Dân / Văn kiện Đảng",note:"Đây là cụm tư liệu nền cho phòng 1954-1960, dùng cho popup tài liệu, bản đồ tư duy và bảng chú giải.",usage:"Cần ảnh bìa, ảnh trang mở đầu, 2-3 trang trích dẫn có đánh dấu và một sơ đồ tóm tắt bối cảnh 1954-1956.",historicalContext:"Nhóm tư liệu này giúp bảo tàng đi từ tiểu sử cá nhân sang chiều sâu đường lối chính trị, lý giải vì sao Lê Duẩn thường được gắn với tư duy chiến lược về miền Nam.",thumbnail:"/assets/media/southern-revolution.svg",verified:!0,sourceLinks:[{label:"Nhân Dân: Nghị quyết 15 mở đường",href:"https://nhandan.vn/nghi-quyet-15-mo-duong-cho-cach-mang-mien-nam-post567818.html"}]},{id:"dong-khoi-photo-roll",title:"Bộ ảnh phong trào Đồng khởi",category:"image",priority:"core",section:"Chiến dịch & bước ngoặt lịch sử",source:"Báo Nhân Dân / Bến Tre / Tư liệu địa phương",note:"Phục vụ cho panel về bước chuyển chiến lược của cách mạng miền Nam từ cuối thập niên 1950 sang đầu thập niên 1960.",usage:"Nên có 1 bản đồ Bến Tre, 2 ảnh phong trào quần chúng, 1 ảnh lực lượng tại chỗ, 1 ảnh tư liệu lãnh đạo liên quan.",historicalContext:"Đồng khởi không chỉ là một mốc sự kiện mà là bước ngoặt cần được kể như nút mở của chặng đường đi tới Mậu Thân và mùa Xuân 1975.",thumbnail:"/assets/media/youth-revolution.svg",verified:!0,sourceLinks:[{label:"Nhân Dân: Phong trào Đồng khởi ở Bến Tre",href:"https://nhandan.vn/phong-trao-dong-khoi-o-ben-tre-post725552.html"}]},{id:"tet-mau-than-mapset",title:"Ảnh và bản đồ Tết Mậu Thân 1968",category:"image",priority:"core",section:"Chiến dịch & bước ngoặt lịch sử",source:"QĐND / TTXVN / Bảo tàng lịch sử quân sự",note:"Dùng cho phòng cao trào chiến tranh chống Mỹ với trọng tâm là đô thị, tác động chính trị và bước ngoặt chiến lược.",usage:"Cần 1 bản đồ tổng, 3-4 ảnh đô thị trọng điểm, 1 infographic về quy mô tiến công và 1 ảnh tư liệu lãnh đạo.",historicalContext:"Bộ ảnh này giúp người xem hiểu Mậu Thân 1968 trong mạch diễn biến chiến tranh, không tách rời vai trò chỉ đạo chiến lược của Trung ương.",thumbnail:"/assets/media/video-documentary.svg",verified:!0,sourceLinks:[{label:"QĐND: Tầm vóc và ý nghĩa lịch sử Tết Mậu Thân 1968",href:"https://media.qdnd.vn/long-form/cuoc-tong-tien-cong-va-noi-day-tet-mau-than-1968-tam-voc-va-y-nghia-lich-su-56412"}]},{id:"spring-1975-gallery",title:"Bản đồ chiến dịch và ảnh mùa Xuân 1975",category:"image",priority:"core",section:"Thống nhất đất nước",source:"QĐND / BTLSQG / Bảo tàng Lịch sử Quân sự Việt Nam",note:"Đây là cụm ảnh phải đầu tư mạnh nhất sau chân dung nhân vật trung tâm vì là đỉnh cao cảm xúc của toàn bộ bảo tàng.",usage:"Cần 1 bản đồ liên hoàn ba chiến dịch, 1 bộ ảnh Buôn Ma Thuột, 1 bộ ảnh Huế - Đà Nẵng, 1 bộ ảnh Chiến dịch Hồ Chí Minh và ảnh thống nhất.",historicalContext:"Chuỗi hình ảnh này cho phép dựng narrative liên tục từ đòn mở màn Tây Nguyên tới khoảnh khắc 30-4-1975, tạo climax thị giác và lịch sử.",thumbnail:"/assets/media/unification-1975.svg",verified:!0,sourceLinks:[{label:"QĐND: Chiến dịch Tây Nguyên",href:"https://www.qdnd.vn/50namgiaiphongmiennam/chien-dich-tay-nguyen-mo-man-dai-thang-mua-xuan-1975-819811"},{label:"QĐND: Chiến dịch Huế - Đà Nẵng",href:"https://www.qdnd.vn/50namgiaiphongmiennam/chien-dich-hue-da-nang-tao-buoc-ngoat-quyet-dinh-cho-dai-thang-mua-xuan-1975-818182"},{label:"QĐND: Chiến dịch Hồ Chí Minh",href:"https://www.qdnd.vn/50namgiaiphongmiennam/chien-dich-ho-chi-minh-lich-su-to-chuc-su-dung-luc-luong-rat-sang-tao-de-gianh-thang-loi-tron-ven-817547"}]},{id:"legacy-document-set",title:"Ảnh làm việc và di sản sau thống nhất",category:"image",priority:"support",section:"Di sản & Đổi mới",source:"BTLSQG / Báo Nhân Dân",note:"Dùng cho không gian kết thúc, chuyển từ thắng lợi quân sự sang câu chuyện lãnh đạo đất nước thời hậu chiến.",usage:"Cần ảnh hội nghị, ảnh làm việc, ảnh đi cơ sở và 1 poster hoặc bìa sách nghiên cứu về Lê Duẩn.",historicalContext:"Nhóm ảnh này giúp phần kết không bị cụt ở mốc 1975 mà kéo dài tới giai đoạn xây dựng đất nước và đánh giá di sản.",thumbnail:"/assets/media/post-war-renewal.svg",verified:!0,sourceLinks:[{label:"BTLSQG: Triển lãm Lê Duẩn",href:"https://baotanglichsu.vn/vi/Articles/3098/58617/trien-lam-le-duan-nha-lanh-djao-kiet-xuat-nguoi-hoc-tro-loi-lac-cua-chu-tich-ho-chi-minh.html"}]},{id:"vnews-profile-video",title:"Video chân dung Lê Duẩn",category:"video",priority:"core",section:"Rạp chiếu tư liệu",source:"VietnamPlus / VNews",note:"Dùng cho khu mở đầu hoặc popup media dài, giúp người xem có một chân dung khái quát trước khi đi sâu vào từng phòng trưng bày.",usage:"Nên dựng dưới dạng video mở đầu 30-60 giây và một phiên bản đầy đủ hơn cho trang media hoặc kiosk video.",historicalContext:"Video chân dung đóng vai trò “narrative anchor”, gom lại các lớp tiểu sử, chiến lược, chiến dịch và di sản trong một trục kể chuyện ngắn.",thumbnail:"/assets/media/video-profile.svg",verified:!0,sourceLinks:[{label:"VietnamPlus: Tổng Bí thư Lê Duẩn - vị lãnh tụ kiệt xuất",href:"https://www.vietnamplus.vn/tong-bi-thu-le-duan-vi-lanh-tu-kiet-xuat-cua-dang-va-cach-mang-viet-nam-post773699.vnp"}]},{id:"campaign-storyboard-videos",title:"Chuỗi clip ngắn cho Đồng khởi, Mậu Thân, mùa Xuân 1975",category:"video",priority:"core",section:"Kiosk chiến dịch",source:"QĐND / VTV / VNews",note:"Mỗi chiến dịch nên có một clip riêng 60-120 giây với bản đồ động, ảnh tư liệu và lời dẫn ngắn.",usage:"Triển khai thành 4 clip: Đồng khởi 1960, Mậu Thân 1968, Tây Nguyên 1975, Chiến dịch Hồ Chí Minh 1975.",historicalContext:"Các clip này biến trang media và không gian 3D thành một bảo tàng sống hơn, giảm cảm giác chỉ đang xem ảnh tĩnh và chữ mô tả.",thumbnail:"/assets/media/video-documentary.svg",verified:!0,sourceLinks:[{label:"QĐND: Tết Mậu Thân 1968",href:"https://media.qdnd.vn/long-form/cuoc-tong-tien-cong-va-noi-day-tet-mau-than-1968-tam-voc-va-y-nghia-lich-su-56412"},{label:"QĐND: Chiến dịch Hồ Chí Minh",href:"https://www.qdnd.vn/50namgiaiphongmiennam/chien-dich-ho-chi-minh-lich-su-to-chuc-su-dung-luc-luong-rat-sang-tao-de-gianh-thang-loi-tron-ven-817547"}]},{id:"legacy-video-wall",title:"Video di sản và tưởng niệm",category:"video",priority:"support",section:"Di sản",source:"Báo Nhân Dân / VNews / Tư liệu tưởng niệm",note:"Phù hợp cho phòng cuối, nơi cần nhịp kể chậm hơn để khép lại hành trình bằng đánh giá lịch sử và ký ức công chúng.",usage:"Có thể dùng 1 clip tưởng niệm ngắn 45 giây và 1 video dài hơn về di sản chính trị, hình ảnh lưu niệm, hội thảo, triển lãm.",historicalContext:"Video kết thúc giúp nối các lớp tư liệu lịch sử với hiện tại, cho thấy vì sao hình ảnh và di sản của Lê Duẩn vẫn tiếp tục được nhắc lại trong không gian công cộng.",thumbnail:"/assets/media/video-legacy.svg",verified:!0,sourceLinks:[{label:"BTLSQG: Triển lãm Lê Duẩn",href:"https://baotanglichsu.vn/vi/Articles/3098/58617/trien-lam-le-duan-nha-lanh-djao-kiet-xuat-nguoi-hoc-tro-loi-lac-cua-chu-tich-ho-chi-minh.html"}]}]])},50570,a=>{"use strict";a.s(["timelineEvents",0,[{id:"birth-1907",year:"1907",title:"Sinh tại Quảng Trị",summary:"Lê Duẩn sinh ngày 7-4-1907 tại xã Triệu Thành, huyện Triệu Phong, tỉnh Quảng Trị. Không gian mở đầu cần dùng ảnh quê hương, gia đình và khu lưu niệm để giới thiệu nền tảng văn hóa, truyền thống yêu nước nơi ông trưởng thành.",detail:"Phòng đầu tiên nên dùng bộ ảnh toàn cảnh Quảng Trị, ảnh khu lưu niệm, bản đồ hành chính và một trục kể chuyện ngắn về gia đình, tuổi thơ, môi trường xã hội đầu thế kỷ XX ở miền Trung. Đây là nền cho toàn bộ hành trình trưng bày.",room:"Quê hương & Tuổi trẻ",image:"/assets/media/quang-tri-home.svg",verified:!0,sourceLinks:[{label:"BTLSQG: 110 năm ngày sinh Tổng Bí thư Lê Duẩn",href:"https://baotanglichsu.vn/vi/Articles/3098/72238/110-nam-ngay-sinh-tong-bi-thu-le-duan-7-4-1907-7-4-2017.html"},{label:"Nhân Dân English: 110th birthday of Le Duan",href:"https://en.nhandan.vn/the-110th-birthday-anniversary-of-party-general-secretary-le-duan-celebrated-post30257.html"}]},{id:"join-1928",year:"1928",title:"Bước vào con đường cách mạng",summary:"Cuối thập niên 1920, ông tham gia phong trào yêu nước và hoạt động cách mạng, mở đầu chặng đường chính trị dài lâu gắn với phong trào cách mạng ở Trung Kỳ và sau này trên cả nước.",detail:"Nội dung nên thể hiện bằng ảnh chân dung giai đoạn sớm, tài liệu tổ chức, bản đồ các địa điểm hoạt động và thuyết minh ngắn về quá trình từ thanh niên yêu nước đến cán bộ lãnh đạo cách mạng.",room:"Quê hương & Tuổi trẻ",image:"/assets/media/youth-revolution.svg",verified:!0,sourceLinks:[{label:"BTLSQG: Triển lãm về Lê Duẩn",href:"https://baotanglichsu.vn/vi/Articles/3098/58617/trien-lam-le-duan-nha-lanh-djao-kiet-xuat-nguoi-hoc-tro-loi-lac-cua-chu-tich-ho-chi-minh.html"}]},{id:"prison-1931",year:"1931",title:"Bị bắt và giam cầm",summary:"Năm 1931 ông bị thực dân Pháp bắt, trải qua nhiều nhà tù như Hỏa Lò, Sơn La, Côn Đảo. Đây là giai đoạn thể hiện rõ ý chí và bản lĩnh của người chiến sĩ cách mạng.",detail:"Không gian nên dùng ảnh di tích nhà tù, hồ sơ lưu trữ, facsimile quyết định giam giữ và trích dẫn về đời sống đấu tranh trong lao tù. Phần này phù hợp với tông màu nén, ánh sáng hẹp và audio ambience.",room:"Hoạt động Cách mạng (1930-1945)",image:"/assets/media/prison-years.svg",verified:!0,sourceLinks:[{label:"BTLSQG: Lê Duẩn qua tư liệu, hiện vật",href:"https://baotanglichsu.vn/vi/Articles/3097/20935/tong-bi-thu-le-duan-qua-tu-lieu-hien-vat-bao-quan-tai-bao-tang-lich-su-quoc-gia.html"}]},{id:"south-1946",year:"1946-1954",title:"Gắn bó với chiến trường Nam Bộ",summary:"Trong cuộc kháng chiến chống Pháp, Lê Duẩn đảm nhiệm nhiều trọng trách ở Nam Bộ, trực tiếp gắn với thực tiễn chiến trường và công tác lãnh đạo ở miền Nam.",detail:"Phần này nên kết hợp bản đồ Nam Bộ kháng chiến, điện chỉ đạo, ảnh chiến khu và sơ đồ tổ chức để cho thấy kinh nghiệm thực tiễn tích lũy từ giai đoạn chống Pháp đã ảnh hưởng đến tư duy chiến lược về sau.",room:"Kháng chiến chống Pháp (1945-1954)",image:"/assets/media/leadership.svg",verified:!0,sourceLinks:[{label:"QĐND: 115 năm ngày sinh Tổng Bí thư Lê Duẩn",href:"https://www.qdnd.vn/chinh-tri/tin-tuc/tong-bi-thu-le-duan-mot-tri-tue-lon-cua-cach-mang-viet-nam-691283"}]},{id:"south-thesis-1956",year:"1956",title:"Đề cương Cách mạng miền Nam",summary:"Đây là điểm nhấn tư tưởng quan trọng của bảo tàng, gắn với quá trình hình thành đường lối cách mạng miền Nam trong bối cảnh sau Hiệp định Giơ-ne-vơ.",detail:"Bố cục nên trưng bày facsimile bản thảo, chú giải bối cảnh lịch sử 1954-1956, các lớp diễn giải liên quan đến Nghị quyết 15 và bước chuyển từ giữ gìn lực lượng sang thế tiến công.",room:"“Kiến trúc sư” Thống nhất",image:"/assets/media/southern-revolution.svg",verified:!0,sourceLinks:[{label:"Nhân Dân: Nghị quyết 15 mở đường",href:"https://nhandan.vn/nghi-quyet-15-mo-duong-cho-cach-mang-mien-nam-post567818.html"}]},{id:"first-secretary-1960",year:"1960",title:"Giữ cương vị Bí thư thứ nhất",summary:"Từ năm 1960, ông giữ cương vị lãnh đạo cao nhất của Đảng trong giai đoạn chiến tranh chống Mỹ cứu nước ngày càng quyết liệt, gắn với nhiều quyết sách chiến lược lớn.",detail:"Đây là điểm nối giữa tiểu sử cá nhân và lịch sử dân tộc. Nên dùng ảnh làm việc, bàn làm việc mô phỏng, điện chỉ đạo và màn hình tương tác dẫn sang hồ sơ các chiến dịch lớn.",room:"“Kiến trúc sư” Thống nhất",image:"/assets/media/leadership.svg",verified:!0,sourceLinks:[{label:"QĐND: Một trí tuệ lớn của cách mạng Việt Nam",href:"https://www.qdnd.vn/chinh-tri/tin-tuc/tong-bi-thu-le-duan-mot-tri-tue-lon-cua-cach-mang-viet-nam-691283"}]},{id:"tet-1968",year:"1968",title:"Tổng tiến công và nổi dậy Tết Mậu Thân",summary:"Xuân 1968 là bước ngoặt lớn về chiến lược, chính trị và ngoại giao. Bảo tàng cần dành riêng một cụm nội dung cho bản đồ đô thị, ảnh tác chiến và tác động lịch sử của Mậu Thân.",detail:"Nên trình bày theo cấu trúc ba lớp: diễn biến tại các đô thị trọng điểm, tác động chiến lược đối với Mỹ và chính quyền Sài Gòn, cùng ý nghĩa lâu dài đối với tiến trình đi tới thắng lợi cuối cùng năm 1975.",room:"“Kiến trúc sư” Thống nhất",image:"/assets/media/video-documentary.svg",verified:!0,sourceLinks:[{label:"QĐND: Tầm vóc và ý nghĩa lịch sử Tết Mậu Thân 1968",href:"https://media.qdnd.vn/long-form/cuoc-tong-tien-cong-va-noi-day-tet-mau-than-1968-tam-voc-va-y-nghia-lich-su-56412"}]},{id:"spring-1975",year:"1975",title:"Đại thắng mùa Xuân 1975",summary:"Từ Tây Nguyên đến Huế - Đà Nẵng rồi Chiến dịch Hồ Chí Minh, mùa Xuân 1975 là cao trào lớn nhất của toàn bộ tuyến kể chuyện trong bảo tàng số.",detail:"Nội dung nên dùng bản đồ động liên hoàn, ảnh tư liệu các mũi tiến công, sa bàn số hóa và một clip tổng hợp 90-120 giây để người xem nắm được logic phát triển từ thắng lợi chiến dịch đến sụp đổ hoàn toàn của đối phương.",room:"“Kiến trúc sư” Thống nhất",image:"/assets/media/unification-1975.svg",verified:!0,sourceLinks:[{label:"QĐND: Chiến dịch Tây Nguyên",href:"https://www.qdnd.vn/50namgiaiphongmiennam/chien-dich-tay-nguyen-mo-man-dai-thang-mua-xuan-1975-819811"},{label:"QĐND: Chiến dịch Hồ Chí Minh",href:"https://www.qdnd.vn/50namgiaiphongmiennam/chien-dich-ho-chi-minh-lich-su-to-chuc-su-dung-luc-luong-rat-sang-tao-de-gianh-thang-loi-tron-ven-817547"}]},{id:"reunification-1976",year:"1976",title:"Đất nước thống nhất bước sang giai đoạn mới",summary:"Sau thắng lợi 1975, đất nước bước vào thời kỳ thống nhất, xây dựng và khôi phục sau chiến tranh. Nội dung về Lê Duẩn cần nối từ chiến thắng quân sự sang bài toán chính trị, kinh tế, xã hội sau hòa bình.",detail:"Không gian này phù hợp với ảnh hội nghị, ảnh làm việc sau thống nhất, sơ đồ tái thiết đất nước và các văn kiện về điều hành kinh tế - xã hội. Đây cũng là nơi chuyển từ chiến tranh sang di sản tư tưởng, lãnh đạo.",room:"Di sản & Đổi mới",image:"/assets/media/post-war-renewal.svg",verified:!0,sourceLinks:[{label:"BTLSQG: Triển lãm về Lê Duẩn",href:"https://baotanglichsu.vn/vi/Articles/3098/58617/trien-lam-le-duan-nha-lanh-djao-kiet-xuat-nguoi-hoc-tro-loi-lac-cua-chu-tich-ho-chi-minh.html"}]},{id:"legacy-1986",year:"1986",title:"Khép lại một chặng đường lịch sử",summary:"Năm 1986 đánh dấu sự kết thúc cuộc đời hoạt động cách mạng của Lê Duẩn. Phần cuối bảo tàng nên nhìn ông trong tổng thể di sản chính trị, vai trò lịch sử và ký ức công chúng.",detail:"Nên dùng ảnh chân dung cuối đời, sách nghiên cứu, hình ảnh tưởng niệm và một video tổng kết để kết thúc hành trình bằng giọng điệu lắng hơn, thiên về đánh giá lịch sử và di sản lâu dài.",room:"Di sản & Đổi mới",image:"/assets/media/legacy.svg",verified:!0,sourceLinks:[{label:"BTLSQG: Lê Duẩn qua tư liệu, hiện vật",href:"https://baotanglichsu.vn/vi/Articles/3097/20935/tong-bi-thu-le-duan-qua-tu-lieu-hien-vat-bao-quan-tai-bao-tang-lich-su-quoc-gia.html"}]}]])}];

